import fs from"fs-extra";import path from"node:path";import{buildPPIconsManifest}from"./ppicons-manifest.js";const START_MARKER="\x3c!-- ppicons:start --\x3e",END_MARKER="\x3c!-- ppicons:end --\x3e";function getInstructionFrontmatter(e){return["---",'description: "Use when working with ppicons, PPIcons icon components, Prisma PHP/PHPX icons, Caspian icons, icon installation, icon updates, or icon imports."','name: "PPIcons AI Context"',`applyTo: "${[e.project.manifestFile,`${e.project.componentsDirectory}/**`].join(", ")}"`,"---",""].join("\n")}function getPhpUsageExample(e){return["```php","<?php","",`use ${e}\\Search;`,"","?>","","<x-search />",'<x-search class="size-4" />',"```"].join("\n")}function getCaspianUsageExample(){return["```html","\x3c!-- @import { Search } from ../../lib/ppicons --\x3e","","<x-search />",'<x-search class="size-4" />',"```"].join("\n")}function getCatalogResponseExample(){return["```json","{",'  "id": 166531,','  "name": "search",','  "componentName": "Search",','  "svg": "<svg xmlns=\\"http://www.w3.org/2000/svg\\" width=\\"24\\" height=\\"24\\" viewBox=\\"0 0 24 24\\" fill=\\"none\\" stroke=\\"currentColor\\" stroke-width=\\"2\\" stroke-linecap=\\"round\\" stroke-linejoin=\\"round\\" class=\\"lucide lucide-search\\"><circle cx=\\"11\\" cy=\\"11\\" r=\\"8\\"/><path d=\\"m21 21-4.3-4.3\\"/></svg>",','  "createdAt": 1774923647142,','  "updatedAt": 1774923647142',"}","```"].join("\n")}function buildManagedBlockContent(e){const o=["# PPIcons AI Context","","This project uses `ppicons` to generate reusable icon components.","",`- Project type: ${e.project.type}`,`- Framework: ${e.project.framework}`,`- Language mode: ${e.project.language}`,`- Framework config file: ${e.project.configFile}`,`- Manifest file: ${e.project.manifestFile}`,`- Components directory: ${e.project.componentsDirectory}`,`- Icons directory: ${e.project.iconsDirectory}`,`- Installed icon count: ${e.icons.length}`,"- Full installed icon inventory: `ppicons.json`","","## Installing Icons","","When a requested icon does not exist yet, install it with `ppicons` instead of hand-writing a component.","",`- Add one icon: \`${e.commands.addOne}\``,`- Add multiple icons: \`${e.commands.addMany}\``,`- Add the full set: \`${e.commands.addAll}\``,`- Refresh installed icons: \`${e.commands.updateInstalled}\``,"","## Discovering Available Icons","","Use the catalog API to find icon names before installing them.","",`- Fetch all available icons: \`${e.catalogApi.listAll.method} ${e.catalogApi.listAll.url}\``,`- Fetch one icon by name: \`${e.catalogApi.getOne.method} ${e.catalogApi.getOne.exampleUrl}\``,"- The single-icon endpoint returns one JSON object.","- The `icon=all` endpoint returns a JSON array of objects with the same shape.","","Single icon response example:","",getCatalogResponseExample(),"","## Using Installed Icons","","Use HTML-first `x-` icon tags.","","- Use the `tagName` values from `settings/component-map.json` as the icon tag contract.","- Keep PPIcons examples and generated markup aligned with those current `x-` tag values.",""];return"prisma-php"===e.project.type?o.push("For Prisma PHP or PHPX templates:","",getPhpUsageExample(e.usage.entry),""):o.push("For Caspian templates:","",getCaspianUsageExample(),"","Adjust the relative import path so it points to the icons directory from the current template file.",""),o.push("## Notes","","- Reuse installed icons from `ppicons.json` before adding new ones.",`- Generated icon files follow this pattern: \`${e.usage.filePattern}\``,`- The import entry for this project is \`${e.usage.entry}\``,""),"prisma-php"===e.project.type?o.push(getPhpLocalImportPreference(e.usage.entry)):o.push(getPythonLocalImportPreference(e.usage.entry)),o.join("\n")}function getPhpLocalImportPreference(e){return["## Local Import Preference","",`For generated or updated PHP imports, prefer grouped namespace imports when two or more icons come from the same \`${e}\` namespace and generated library directory.`,"",`- Use a grouped import when multiple icons are imported from \`${e}\`.`,"- Use a single import when only one icon is needed.","- Do not treat existing separate single imports as wrong unless the task explicitly includes import cleanup.",`- When adding a second or third icon from \`${e}\` to the same file, prefer collapsing those imports into one grouped statement.`,"","Preferred for multiple icons:","","```php","<?php","",`use ${e}\\{ArrowRight, Mail, UserRound};`,"","?>","```","","Fine for one icon:","","```php","<?php","",`use ${e}\\Mail;`,"","?>","```","","Example usage:","","```php","<?php","",`use ${e}\\{ArrowRight, Mail, UserRound};`,"","?>","","<div>",'    <x-mail class="size-4" />','    <x-user-round class="size-4" />','    <x-arrow-right class="size-4" />',"</div>","```"].join("\n")}function getPythonLocalImportPreference(e){return["## Local Import Preference","",`For generated or updated Python imports, prefer grouped imports when two or more icons come from the same \`${e}\` package.`,"",`- Use a grouped import when multiple icons are imported from \`${e}\`.`,"- Use a single import when only one icon is needed.","- Do not treat existing separate single imports as wrong unless the task explicitly includes import cleanup.",`- When adding a second or third icon from \`${e}\` to the same file, prefer collapsing those imports into one grouped statement.`,"","Preferred for multiple icons:","","```python",`from ${e} import ArrowRight, Mail, UserRound`,"```","","Fine for one icon:","","```python",`from ${e} import Mail`,"```","","Example usage in Python component:","","```python",`from ${e} import ArrowRight, Mail, UserRound`,"","def render():",'    return """',"    <div>",'        <x-mail class="size-4" />','        <x-user-round class="size-4" />','        <x-arrow-right class="size-4" />',"    </div>",'    """',"```"].join("\n")}async function writePPIconsInstructionFile(e,o){const n=await buildPPIconsManifest(e),t=getInstructionFrontmatter(n),r=[START_MARKER,buildManagedBlockContent(n),END_MARKER].join("\n");await fs.ensureDir(path.dirname(o));const i=`${t}${r}\n`;return await fs.writeFile(o,i,"utf8"),o}export async function writePPIconsCopilotInstructions(e){return writePPIconsInstructionFile(e,path.join(e.projectRoot,".github","instructions","ppicons.instructions.md"))}